LBloodStick.UIBLOOD_STICK_ROOT = "UIBloodStick"

function LBloodStick:LBloodStick()
    self._bloodAnimation = nil
    self._maxHP = nil                     -- 最大生命值
    self._currentHP = nil                 -- 当前生命值
    self._hurt  = nil                     -- 伤害值
    self._bloodStickTrans = nil           -- 血条预制体
    self._heroTrans = nil                 -- 英雄的位置
    self._uiCamera = nil                  -- UI摄像机
    self._sceneCamera = nil               -- 场景摄像机
    self._heroData = nil                  -- 英雄数据

    self._maxPShieldCount = 6             -- 格子长度：目前格挡条预制体上面只弄了六个格子，后期有需要再添加
    self._curPShieldCount = 0             -- 当前格挡次数
    self._maxDefShieldValue = 0           -- 最大防护盾值
    self._curDefShieldValue = 0           -- 当前防护盾值

    self._deviationPos = Vector3.New(0, 0, 0)

    self._bShow = true
    self._barType = 0

    self._showBloodDetail = nil

    ---@type LDisplayPrefab
    self._displayObj = nil
end

--[[
    heroData=
