]]


function LBloodStick:CreateBloodStick(barType,maxHP,curHP,heroData)
    self._barType = barType
    local rootCanvas = LGameUI.GetUIFight()
    self._uiCamera = LGameUI.GetUICamera()
    self._sceneCamera = gLGameScene:GetCurrentSceneCamera()

    self._parentTrans = CS.FindTrans(rootCanvas,LBloodStick.UIBLOOD_STICK_ROOT)
    if (not self._parentTrans) then
        self._parentTrans = CS.NewObject(LBloodStick.UIBLOOD_STICK_ROOT, rootCanvas)
    end


    self._maxHP = maxHP
    self._currentHP = curHP
    self._hpRate = 1
    if maxHP > 0 then
        self._hpRate = curHP / maxHP
    end
    if heroData then
        self._heroData = heroData
    end

    self._showBloodDetail = gModelBattle:GetGMShowBlood()

    self:InitDisplay()

end

function LBloodStick:InitDisplay()
    local dp = LDisplayPrefab:New()
    self._displayObj = dp
    local dirPath = "UI/Prefabs/Com"
    local name = "HPBar"
    dp:CreatePrefab(self._parentTrans, dirPath, name)
    dp:SetLoadedFunction(function ()
        self:OnLoaded()
    end)
end



function LBloodStick:StartLoad()
    self._displayObj:StartLoad()
end

function LBloodStick:OnLoaded()
    if self._isBloodDestroy then
        return
    end

    if not self._displayObj then
        return
    end

    if not self._displayObj:IsDpValid() then
        return
    end

    self._bloodStickTrans = self._displayObj:GetDisplayTrans()

    self:InitTranInfo()
    self:InternalInitBloodStick()
    self:OnUpdateHeroTrans()
    if self._bloodType == 1 then
        self:UpdateNormalShield()
        self:UpdateBlockShield()
        self:UpdateCourageBuff()
        self:UpdateBuffBarShow()
    end
    self:UpdateShow()
end

function LBloodStick:InitTranInfo()
    local root = self._bloodStickTrans
    self._cdBg = CS.FindTrans(root,"Blood1/Level/CdBg")
    self._cdText = CS.FindTrans(self._cdBg,"UIText")
    CS.ShowObject(self._cdBg,false)
end

function LBloodStick:InternalInitBloodStick()
    -- local hp = CS.FindTrans(self._bloodStickTrans, "hp")
    self._bloodAnimation = self._bloodStickTrans:GetComponent(typeBloodAnimation)
    if (not self._bloodAnimation) then
        self._bloodAnimation = self._bloodStickTrans.gameObject:AddComponent(typeBloodAnimation)
    end

    self:SetHeroData(self._heroData)
end



function LBloodStick:SetHeroData(heroData)



    local level,race,isResonance
    local index = 1
    local isShow = false
    if heroData then
        isShow = true
        index = heroData.index or 1
        level = heroData.level
        race = heroData.race
        isResonance = heroData.isResonance
    end

    self._bloodType = index

    self:InitTrans(isShow,index)

    -- 【C宠物系统】删掉宠物系统相关
    -- if heroData and heroData.type == "pet" then
    --     self:SetPetShow(heroData)
    --     return
    -- end

    if index == 3 then
        local _powerText = self._powerText
        if not _powerText then
            return
        end
        local powerStr = LUtil.PowerNumberCoversion(heroData.power)
        self:SetXTextContent(_powerText, powerStr)
        return
    end
    if isShow then
        -- 等级
        self:SetLevel(level,isResonance)
        -- 英雄种族
        self:SetHeroIconImage(race)
    end

end

