function LBloodStick:InitTrans(isShow,index)
    local rootTrans1 = CS.FindTrans(self._bloodStickTrans,"Blood1")
    local rootTrans2 = CS.FindTrans(self._bloodStickTrans,"Blood2")
    local rootTrans3 = CS.FindTrans(self._bloodStickTrans,"Blood3")
    self._bloodDetail = CS.FindTrans(self._bloodStickTrans,"detail")
    CS.ShowObject(self._bloodDetail,false)


    CS.ShowObject(rootTrans1,false)
    CS.ShowObject(rootTrans2,false)
    CS.ShowObject(rootTrans3,false)

    local rootTrans = rootTrans1
    if index == 1 then
        rootTrans = rootTrans1
    elseif index == 2 then
        rootTrans = rootTrans2
    elseif index == 3 then
        rootTrans = rootTrans3
    end
    if index == 3 then
        CS.ShowObject(rootTrans3,true)
        local text = CS.FindTrans(rootTrans3,"PowerShow/text")
        self._powerText = text
        return
    end

    self._levelTrans = CS.FindTrans(rootTrans,"Level")
    self._levelTextTrans = CS.FindTrans(self._levelTrans,"levelText")
    self._heroIconTrans = CS.FindTrans(self._levelTrans,"HeroIcon")

    self._buffBloodStickListTrans = CS.FindTrans(rootTrans,"BuffBloodStickList")

    CS.ShowObject(rootTrans,true)

    CS.ShowObject(self._levelTrans,isShow)


    if self._buffBloodStickListTrans then
        CS.ShowObject(self._buffBloodStickListTrans,isShow)
        self:InitBuffBar()
    end

    local courageRoot = CS.FindTrans(self._bloodStickTrans,"Blood1/courage")
    self._courageRoot = courageRoot
    local courageIcon = CS.FindTrans(courageRoot,"icon")
    local courageText = CS.FindTrans(courageRoot,"text")
    self:SetImage(courageIcon,"buff_baofa")
    self._courageText = courageText

    self._infoTran = CS.FindTrans(self._bloodStickTrans,"info")
end

function LBloodStick:InitBuffBar()
    local buffTemplate1 = CS.FindTrans(self._buffBloodStickListTrans,"BuffBarTemplate1")
    local buffTemplate2 = CS.FindTrans(self._buffBloodStickListTrans,"BuffBarTemplate2")

    self._buffBar1 = buffTemplate1
    self._buffBar2 = buffTemplate2
end

function LBloodStick:GetBuffBarInfo(type)
    if not self._buffBarList then
       self._buffBarList = {}
    end
    local data = self._buffBarList[type]
    if data then
        return data
    end

    local root = nil
    if type == 2 then
        root = self._buffBar1
    elseif type == 3 then
        root = self._buffBar2
    else
        return
    end

    --CS.ShowObject(root,true)

    local rootTran = root.transform
    local bgRoot = CS.FindTrans(rootTran,"sliderBg")
    local itemList = CS.FindTrans(bgRoot,"itemList")
    local itemRoot = CS.FindTrans(itemList,"ItemRoot")
    local unuseRoot = CS.FindTrans(itemList,"unuse")
    local template = CS.FindTrans(itemList,"ItemTemplate")
    local itemPool = UIObjPool:New()
    itemPool:Create(unuseRoot,template)

    data =
    {
        rootTran = rootTran,
        bgRoot = bgRoot,
        itemRoot = itemRoot,
        itemPool = itemPool,
    }


    self._buffBarList[type] = data
    return data
end

function LBloodStick:HideBuffBar()
    if not self._buffBarList then
        return
    end

    for k,v in pairs(self._buffBarList) do
        CS.ShowObject(v.rootTran,false)
    end

end

function LBloodStick:SetLevel(level,isResonance)
    if not self._levelTextTrans then
        return LogError("获取self._levelTextTrans节点失败")
    end

    self._levelText = self._levelTextTrans:GetComponent(typeXUIText)
    if (not self._levelText) then
        self._levelText = self._levelTextTrans.gameObject:AddComponent(typeXUIText)
    end

    local lvStr = ""
    if level then
        lvStr = string.replace(ccClientText(14206),level)
    end

    self:SetXTextContent(self._levelText,lvStr)

    local lvColor = LUtil.GetResonanceColor(isResonance)
    lvColor = LUtil.ColorByHex(lvColor)
    self._levelText.color = lvColor
    
    if gLGameLanguage:IsJapanVersion() then
        self._bgTrans = CS.FindTrans(self._levelTrans,"Bg")
        if self._bgTrans then
            self._bgTrans.localPosition = Vector3.New(22,0,0)
            LxUiHelper.SetSizeWithCurAnchor(self._bgTrans,0,200)
            self._levelTextTrans.localPosition = Vector3.New(28,0,0)
        else
            self._levelTextTrans.localPosition = Vector3.New(14,12.8,0)
        end
    end 
end

function LBloodStick:SetHeroIconImage(race)
    if not self._heroIconTrans then
        return LogError("获取self._heroIconTrans节点失败")
    end


    local typeImg = gModelHero:GetRaceImgByRefId(race)
    if typeImg then
        self:SetImage(self._heroIconTrans,typeImg)
    else
        LogError("no race icon race:"..tostring(race))
        CS.ShowObject(self._heroIconTrans,false)
    end
end

function LBloodStick:Destroy()
    if self._isBloodDestroy then
        return
    end
    if self._displayObj then
        self._displayObj:Destroy()
    end
    LxNodeBase.Dispose(self)
    self._isBloodDestroy = true
end

function LBloodStick:IsBloodDestroy()
    return self._isBloodDestroy
end

