function LBloodStick:UpdateHpRate(rate)
    if not self:IsDpValid() then
        return
    end
    self._bloodAnimation:UpdateBloodRate(rate)
end

function LBloodStick:UpdateBlueRate(rate)
    if not self:IsDpValid() then
        return
    end
    self._bloodAnimation:UpdateBlueBloodRate(rate)
end

function LBloodStick:UpdateGreenRate(rate)
    if not self:IsDpValid() then
        return
    end
    self._bloodAnimation:UpdateGreenBloodRate(rate)
end

function LBloodStick:UpdateShow()
    if not self:IsDpValid() then
        return
    end
    CS.ShowObject(self._bloodStickTrans,self._bShow)
    if self._bShow then
        self._bloodAnimation:ChangeTrans()
    end
end

function LBloodStick:ShowObjInfo(str)
    if CS.IsValidObject(self._infoTran) then
        self:SetXTextContent(self._infoTran,str)
    end
end

