function LBloodStick:IsDpValid()
    return self._bloodStickTrans and CS.IsValidObject(self._bloodStickTrans)
end

function LBloodStick:SetVisible(bVisible)
    if self._bShow == bVisible then return end
    self._bShow = bVisible
    self:UpdateShow()
end

--设置英雄  deviationPos(Vector3)
function LBloodStick:SetHeroTrans(heroTrans,deviationPos)
    self._heroTrans = heroTrans
    self._deviationPos = deviationPos
    self:OnUpdateHeroTrans()
end

function LBloodStick:OnUpdateHeroTrans()
    if(not CS.IsValidObject(self._bloodStickTrans)) then return end
    self._bloodAnimation:Init(self._barType,self._heroTrans,self._uiCamera,self._sceneCamera,self._deviationPos)
    self:UpdateHpRate(self._hpRate)

    self:ShowBloodDetail()
end

function LBloodStick:UpdateHPValue(hurt)
    local curHp = self._currentHP

    local maxHp = self._maxHP

    curHp = curHp + hurt
    if (curHp < 0) then
        curHp = 0
    elseif (curHp > maxHp) then
        curHp = maxHp
    end

    self._currentHP = curHp

    local rate = 1
    if maxHp > 0 then
        rate = curHp / maxHp
    end
    self:SetHpRate(rate)

    self:ShowBloodDetail()
end

function LBloodStick:UpdateHpProgress(curHp)
    local maxHp = self._maxHP
    local rate= 1
    if maxHp>0 then
        rate = curHp/maxHp
    end
    if rate>0 and rate<0.05 then
        rate =0.05
    end
    self._currentHP = curHp
    self:SetHpRate(rate)
    self:ShowBloodDetail()
end

function LBloodStick:RefreshHpData(maxHp,curHp)
    self._maxHP = maxHp
    self:UpdateHpProgress(curHp)
end

function LBloodStick:ShowBloodDetail()
    if not self._showBloodDetail then
        return
    end

    if not self._bloodDetail then
        return
    end
    CS.ShowObject(self._bloodDetail,true)
    local detailText = self._bloodDetail:GetComponent(typeXUIText)
    if (not detailText) then
        return
    end

    local curHp = self._currentHP and tostring(math.floor(self._currentHP)) or ""
    local maxHp = self._maxHP and tostring(math.floor(self._maxHP)) or ""

    local str = string.format("%s/%s",curHp,maxHp)

    self:SetXTextContent(detailText,str)
end

function LBloodStick:GetCurHp()
    return self._currentHP
end

function LBloodStick:SetHpRate(rate)
    self._hpRate = rate
    self:UpdateHpRate(rate)
end

function LBloodStick:ShowCourageBuff(num)
    if self._courageNum and self._courageNum == num then
        return
    end
    self._courageNum = num
    self:UpdateCourageBuff()
end

function LBloodStick:UpdateCourageBuff()
    if not self:IsDpValid() then
        return
    end

    local show = self._courageNum and self._courageNum>0
    CS.ShowObject(self._courageRoot,show)
    if show then
        self:SetXTextContent(self._courageText,self._courageNum)
    end
end

function LBloodStick:ShowBlockShield(data)
    local curMaxCount = math.min(6,data.maxCount)
    local curCount = math.min(6,data.curCount)
    if curMaxCount == self._maxPShieldCount and curCount == self._curPShieldCount then
        return
    end

    self._maxPShieldCount = math.min(6,data.maxCount)
    self._curPShieldCount = math.min(6,data.curCount)
    self:UpdateBlockShield()
end

function LBloodStick:UpdateBlockShield()
    if not self:IsDpValid() then
        return
    end

    local buffTrans = CS.FindTrans(self._buffBloodStickListTrans,"Buff1")

    local showBlock = self._curPShieldCount> 0 and self._maxPShieldCount > 0
    self._showBlock = showBlock
    CS.ShowObject(buffTrans,showBlock)
    if not showBlock then
        return
    end

    CS.ShowObject(buffTrans,true)
    local bgBlueTrans = CS.FindTrans(buffTrans,"BlueBg")
    local gridBlueTrans = CS.FindTrans(bgBlueTrans,"Grid")

    self._bloodAnimation:InitBlueBloodStick(buffTrans)
    CS.ShowObject(buffTrans,true)
    CS.ShowObject(bgBlueTrans,true)
    --CS.ShowObject(bgGreenTrans,false)

    local curRate = self._curPShieldCount /self._maxPShieldCount
    self:UpdateBlueRate(curRate)

    -- 计算格挡盾格挡次数的格子距离
    local showCnt = self._maxPShieldCount
    for i = 1,6 do
        local grid = CS.FindTrans(gridBlueTrans,"Grid"..i)
        local show = i< showCnt
        CS.ShowObject(grid,show)
    end
end

function LBloodStick:ShowNormalShield(data)
    if self._maxDefShieldValue == data.maxShieldV and self._curDefShieldValue == data.curShieldV then
        return
    end

    self._maxDefShieldValue = data.maxShieldV
    self._curDefShieldValue = data.curShieldV

    self:UpdateNormalShield()
end
function LBloodStick:UpdateNormalShield()
    if not self:IsDpValid() then
        return
    end

    local buffTrans = CS.FindTrans(self._buffBloodStickListTrans,"Buff2")

    local showShield = self._curDefShieldValue >0
    self._showShield = showShield


    CS.ShowObject(buffTrans,showShield)
    if not showShield then
        return
    end

    CS.ShowObject(buffTrans,true)
    local bgGreenTrans = CS.FindTrans(buffTrans,"GreenBg")
    CS.ShowObject(buffTrans,true)
    CS.ShowObject(bgGreenTrans,true)

    self._bloodAnimation:InitGreenBloodStick(buffTrans)
    local curRate = self._curDefShieldValue/self._maxDefShieldValue
    self:UpdateGreenRate(curRate)
end

