function LBloodStick:UpdateBuffBarShow()
    self:RefreshBuffBarShow(self._buffBarDataList)
end


function LBloodStick:RefreshBuffBarShow(list)
    local newList = {}
    if list then
        local uiType2List = {}
        for buffId,data in pairs(list) do
            local buffUIPara = data.buffUIPara
            local uiType = buffUIPara.uiType
            if uiType == 1 then
                newList[buffId] = data
            else
                table.insert(uiType2List,{
                    buffId = buffId,
                    data = data,
                })
            end
        end

        if #uiType2List > 0 then
            table.sort(uiType2List,function(a,b)
                return a.buffId > b.buffId
            end)
            local firstData = uiType2List[1]
            newList[firstData.buffId] = firstData.data
        end
    end

    self._buffBarDataList = newList

    if not self:IsDpValid() then return end

    self:HideBuffBar()

    if not newList then return end



    for k,v in pairs(newList) do
        self:ShowBuffBarSingle(v)
    end
end

function LBloodStick:OnDrawBar(item,itemdata,barCfg)
    local bg = CS.FindTrans(item,"bg")
    local fill = CS.FindTrans(item,"fill")
    local fill_1 = CS.FindTrans(item,"fill_1")

    if barCfg.uiType == 2 then
        self:SetImage(bg,barCfg.bgPath1,nil,true)
        self:SetImage(fill,barCfg.fillPath,nil,true)
        self:SetImage(fill_1,barCfg.fillPath1,nil,true)
        CS.ShowObject(fill,not itemdata.isFull and itemdata.isOn)
        CS.ShowObject(fill_1,itemdata.isFull and itemdata.isOn)
    else
        CS.ShowObject(fill,itemdata.isOn)
    end



end

function LBloodStick:ShowBuffBarSingle(data)
    local barType = data.buffUIPara.uiType
    local buffBarInfo = self:GetBuffBarInfo(barType)
    if not buffBarInfo then return end

    local max = 5
    local isBarType2 = barType == 2
    --if isBarType2 then
    --    max = 10
    --elseif barType == 3 then
    --    max = 7
    --end


    local cur = data.cnt
    local statisticsData = data.statisticsData
    if statisticsData then
        local beAttackCount = statisticsData.beAttackCount
        if beAttackCount then
            cur = beAttackCount
        end
        local maxAttackCount = statisticsData.maxAttackCount
        if maxAttackCount then
            max = maxAttackCount
        end
    end

    local buffTrans = buffBarInfo.rootTran
    CS.ShowObject(buffTrans,cur > 0)

    if buffBarInfo.cnt == cur then return end


    buffBarInfo.cnt = cur

    if cur <= 0 then return end

    if isBarType2 then
        self:SetImage(buffBarInfo.bgRoot,data.buffUIPara.bgPath,nil,true)
    end


    local dataList = {}
    for k = 1, max do
        table.insert(dataList,{
            index = k,
            isOn = k<=cur,
            isFull = max <= cur
        })
    end

    local itemRoot =  buffBarInfo.itemRoot
    local itemPool = buffBarInfo.itemPool
    itemPool:ReturnAllObj()
    for k,v in ipairs(dataList) do
        local obj = itemPool:GetObj()
        local tran = obj.transform
        CS.SetParentTrans(tran,itemRoot)
        CS.ShowObject(obj,true)
        self:OnDrawBar(tran,v,data.buffUIPara)
    end
end

function LBloodStick:ShowCdInfo(round)
    if not CS.IsValidObject(self._cdBg) then
        return
    end
    CS.ShowObject(self._cdBg,true)
    self:SetXTextContent(self._cdText,round)
end

